/* ============================================================
   Vendor Portal – shared icon set (Feather-style, stroke icons)
   Keeps page markup clean and consistent. Every icon accepts the
   standard svg props (size via width/height, className, etc).
   ============================================================ */

const Svg = ({ size = 16, className = "", strokeWidth = 2, children, ...rest }) => (
    <svg
        width={size}
        height={size}
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeLinejoin="round"
        className={className}
        {...rest}
    >
        {children}
    </svg>
);

